import { useState } from "react";
import NotificationBadge from "./NotificationBadge";
import classes from "./ServerIcon.module.css";


const ServerIcon = (props) => {
  const [isSelected, setIsSelected] = useState(false);

  const selectHandler = (id) => {
    props.setSelectedServer(id);
    setIsSelected(true);
  }

  return (
    <div className={classes["wrapper"]} onClick={selectHandler}>
      <div className={classes["pill-wrapper"]}>
        <span className={classes["pill"]}></span>
      </div>
      <div className={classes["server-item-wrapper"]}>
        <div className={classes["icon-wrapper"]}>
          <img
            className={classes["icon"]}
            src="https://animedao.to/images/call-of-the-night.jpg"
            alt="test"
          ></img>
          {/* <div className={classes["icon"]}>G</div> */}
        </div>
        <div className={classes["lower-badge"]}>
          <NotificationBadge amount={1}></NotificationBadge>
        </div>
      </div>
    </div>
  );
};

export default ServerIcon;
